var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>클리포트 게임</color> 승전, 1개월 뒤\\n<color=#ffd34c>그라운드 원</color> 시립 도서관","JPN":"<color=#ffd34c>クリフォトゲーム</color>戦勝から1か月後\\n<color=#ffd34c>グラウンド・ワン</color>市立図書館","ENG":"[[","TWN":"距<color=#ffd34c>逆卡巴拉遊戲</color>勝利，1個月後\\n<color=#ffd34c>G1</color> 市立圖書館","SCN":"距<color=#ffd34c>神圣战役</color>胜利，1个月后\\n<color=#ffd34c>G1</color> 市立图书馆","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네가 이번에 들어온 편입생이구나? 만나서 반가워.","JPN":"あなたが今度入ってきた編入生？　初めまして。","ENG":"So you're the new transfer student? Nice to meet you.","TWN":"你是這次新來的插班生吧？很高興見到你。"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"편입한 지 꽤 지났는데, 서류만 접수되고 그 뒤에 아무 연락이 없어서 이렇게 찾아왔어.","JPN":"編入してから随分経つのに、書類が受理されて以降なんの連絡もないから会いに来ちゃった。","ENG":"It's been a while since you transferred on paper, but there was no contact from you after that, so I came to see you.","TWN":"你插班已經有一段時間了，但送來檔案之後就沒有任何聯繫，所以我們就來找你了。"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아, 네…….","JPN":"あっ、はい……","ENG":"Oh, okay...","TWN":"是，是嗎……"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으음, 아! 혹시 책 좋아하니?","JPN":"うーん、あ！　もしかして本が好きなの？","ENG":"Mm... Oh! Do you like books?","TWN":"嗯嗯。對了！你是不是喜歡看書？"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"우리 아카데미 학생들은 적어도 하나씩 부 활동을 하도록 권장하고 있거든.","JPN":"このアカデミーの生徒は、みんな何かしらの部活に入ることになってるんだよ。","ENG":"The Academy encourages its students to have at least one club activity.","TWN":"我們學院鼓勵學生至少參加一個社團。"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니까 리온도 분명 마음에 드는 동아리를 찾을 수 있을 거야! 고전 문학 연구회는 어때?","JPN":"だからリオンちゃんも、お気に入りの部活を探してみてね！　古典文学研究会はどう？","ENG":"So I'm sure you'll find a club you like, Liona! How does Classical Literature Research Club sound?","TWN":"所以萊恩你肯定也能找到心儀的社團！古典文學研究會怎麼樣？"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저…….","JPN":"あの……","ENG":"Uh...","TWN":"那個……"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"미카 선배라고 하셨죠?","JPN":"ミカ先輩……ですよね？","ENG":"Mika, was it?","TWN":"你是米卡前輩吧？"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응! 아카데미 총학생회의 미카★스타! 장차 세기의 대마술사가 될 몸이라구!","JPN":"うん！　アカデミー総生徒会のミカ★スター！　世紀の大魔術師になる器だよ！","ENG":"Yup! I'm Mika★Star from the Academy Student Council! I'm also going to be the greatest magician of the century!","TWN":"沒錯！學院學生會的米卡★斯塔！將來要成為世紀大魔術師的人喔！"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앞으로 아카데미 생활에 궁금한 점이 있다면 얼마든지 상담해도 좋아.","JPN":"これからアカデミーでの生活について質問があったら、いつでも相談してね。","ENG":"If you have any questions about the Academy, feel free to ask me.","TWN":"如果你對未來的學院生活有任何疑問，隨時都可以諮詢我。"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"죄송하지만, 동아리 활동은 힘들 것 같아요.","JPN":"すみません、部活はできそうにないです。","ENG":"I'm sorry, but I think club activities are going to be difficult for me.","TWN":"對不起，我恐怕很難參加社團活動。"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저랑 같이 있으면 다들 위험해지거든요. 다른 애들한테 폐를 끼칠 수는 없어서요…….","JPN":"私と一緒にいると、みんなが危険です。他の人たちに迷惑をかけるわけには……","ENG":"People will be in danger if I'm around them. And I don't want to cause harm to others...","TWN":"如果跟我在一起，大家都會變得很危險。我不能給別人添麻煩……"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아아, 프로필에서 봤어. <color=#ffd34c>토토</color>라고 했나? 그 마검 때문이구나?","JPN":"ああ、プロフィールで見たよ。<color=#ffd34c>トト</color>だっけ？　あの魔剣のせいだよね？","ENG":"Oh, I saw it in your profile. <color=#ffd34c>Toto</color>, was it? It's because of that evil sword, right?","TWN":"啊啊，我在履歷上看到過。叫<color=#ffd34c>托托</color>是吧？是因為那把魔劍吧？"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"걱정하지 마. 아카데미에는 네가 생각하는 것보다 훨씬 별난 녀석들이 많거든!","JPN":"大丈夫。アカデミーにはあなたが思うよりずっと変なやつらがいっぱいいるから！","ENG":"Don't worry. There are plenty of students far weirder than you can imagine at the Academy!","TWN":"不用擔心，學院裡有很多比你想得還要奇怪的傢伙！"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"다들 분명 리온의 개성을 이해해 줄 거야.","JPN":"きっとみんなリオンの個性を理解してくれる。","ENG":"I'm sure everyone will understand your uniqueness.","TWN":"大家肯定會理解你的個性的！"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아니요, 제 말은 그런 뜻이 아니라…….","JPN":"いいえ、私の話はそういう意味じゃなくて……","ENG":"No, that's not what I meant...","TWN":"不，我說的不是那個意思……"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아, 아무튼 저 급한 일이 있어서……! 먼저 가봐도 될까요?","JPN":"と、とにかく急用があるので……！　先に帰ってもいいですか？","ENG":"A-anyway, I have to be somewhere...! May I be excused?","TWN":"總，總之，我有急事……！我可以先走了嗎？"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아카데미에는, 당분간 못 나가게 될 것 같다고 이사장님께 말씀드릴게요.","JPN":"アカデミーには、しばらく出ないと理事長に話しておきます。","ENG":"I'll tell the chairwoman that I won't be able to attend the Academy for the time being.","TWN":"我會跟理事長說一下，我可能暫時來不了學院了。"},"stage":{"bg":"LIBRARY_01","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그, 그럼……!","JPN":"じゃ、じゃあ……！","ENG":"B-bye...!","TWN":"那，那我走了……！"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"얘! 잠깐만 기다려봐, 리온!","JPN":"ねえ！　ちょっと待ってよ、リオンちゃん！","ENG":"Hey! Wait up, Liona!","TWN":"喂！等一下，萊恩！"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어이가 없네. 거기 서. 겁쟁이 안경!","JPN":"ふざけてるの？　待ちなさいよ。弱虫メガネ！","ENG":"You got to be kidding me. Stop right there, Shy Specs!","TWN":"真是無言。給我站住，膽小四眼蛙！"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"거, 겁쟁이 안경……!?","JPN":"よ、弱虫メガネ……！？","ENG":"S-shy Specs...?!","TWN":"膽，膽小四眼蛙……？！"},"stage":{"bg":"LIBRARY_01","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};